6: import { Promises } from '../../../base/common/async.js';
7: import { canceled } from '../../../base/common/errors.js';
8: import { Event } from '../../../base/common/event.js';
9: import { Disposable, IDisposable } from '../../../base/common/lifecycle.js';
10: import { IExtensionHostProcessOptions, IExtensionHostStarter } from '../common/extensionHostStarter.js';
11: import { ILifecycleMainService } from '../../lifecycle/electron-main/lifecycleMainService.js';
12: import { ILogService } from '../../log/common/log.js';
13: import { ITelemetryService } from '../../telemetry/common/telemetry.js';
14: import { WindowUtilityProcess } from '../../utilityProcess/electron-main/utilityProcess.js';
15: import { IWindowsMainService } from '../../windows/electron-main/windows.js';
16: 
17: export class ExtensionHostStarter extends Disposable implements IDisposable, IExtensionHostStarter {
18: 
19: 	readonly _serviceBrand: undefined;
20: 
21: 	private static _lastId: number = 0;
22: 
23: 	private readonly _extHosts = new Map<string, WindowUtilityProcess>();
24: 	private _shutdown = false;
25: 
26: 	constructor(
27: 		@ILogService private readonly _logService: ILogService,
28: 		@ILifecycleMainService private readonly _lifecycleMainService: ILifecycleMainService,
29: 		@IWindowsMainService private readonly _windowsMainService: IWindowsMainService,
30: 		@ITelemetryService private readonly _telemetryService: ITelemetryService,
31: 	) {
32: 		super();
33: 
34: 		// On shutdown: gracefully await extension host shutdowns
35: 		this._register(this._lifecycleMainService.onWillShutdown(e => {
36: 			this._shutdown = true;
37: 			e.join('extHostStarter', this._waitForAllExit(6000));
38: 		}));
39: 	}
40: 
41: 	override dispose(): void {
42: 		// Intentionally not killing the extension host processes
43: 		super.dispose();
44: 	}
45: 
46: 	private _getExtHost(id: string): WindowUtilityProcess {
47: 		const extHostProcess = this._extHosts.get(id);
48: 		if (!extHostProcess) {
49: 			throw new Error(`Unknown extension host!`);
50: 		}
51: 		return extHostProcess;
52: 	}
53: 
54: 	onDynamicStdout(id: string): Event<string> {
55: 		return this._getExtHost(id).onStdout;
56: 	}
57: 
58: 	onDynamicStderr(id: string): Event<string> {
59: 		return this._getExtHost(id).onStderr;
60: 	}
61: 
62: 	onDynamicMessage(id: string): Event<any> {
63: 		return this._getExtHost(id).onMessage;
64: 	}
65: 
66: 	onDynamicExit(id: string): Event<{ code: number; signal: string }> {
67: 		return this._getExtHost(id).onExit;
68: 	}
69: 
70: 	async createExtensionHost(): Promise<{ id: string }> {
71: 		if (this._shutdown) {
72: 			throw canceled();
73: 		}
74: 		const id = String(++ExtensionHostStarter._lastId);
75: 		const extHost = new WindowUtilityProcess(this._logService, this._windowsMainService, this._telemetryService, this._lifecycleMainService);
76: 		this._extHosts.set(id, extHost);
77: 		const disposable = extHost.onExit(({ pid, code, signal }) => {
78: 			disposable.dispose();
79: 			this._logService.info(`Extension host with pid ${pid} exited with code: ${code}, signal: ${signal}.`);
80: 			setTimeout(() => {
81: 				extHost.dispose();
82: 				this._extHosts.delete(id);
83: 			});
84: 
85: 			// See https://github.com/microsoft/vscode/issues/194477
86: 			// We have observed that sometimes the process sends an exit
87: 			// event, but does not really exit and is stuck in an endless
88: 			// loop. In these cases we kill the process forcefully after
89: 			// a certain timeout.
90: 			setTimeout(() => {
91: 				try {
92: 					process.kill(pid, 0); // will throw if the process doesn't exist anymore.
93: 					this._logService.error(`Extension host with pid ${pid} still exists, forcefully killing it...`);
94: 					process.kill(pid);
95: 				} catch (er) {
96: 					// ignore, as the process is already gone
97: 				}
98: 			}, 1000);
99: 		});
100: 		return { id };
101: 	}
102: 
103: 	async start(id: string, opts: IExtensionHostProcessOptions): Promise<{ pid: number | undefined }> {
104: 		if (this._shutdown) {
105: 			throw canceled();
106: 		}
107: 		const extHost = this._getExtHost(id);
108: 		extHost.start({
109: 			...opts,
110: 			type: 'extensionHost',
111: 			entryPoint: 'vs/workbench/api/node/extensionHostProcess',
112: 			args: ['--skipWorkspaceStorageLock'],
113: 			execArgv: opts.execArgv,
114: 			allowLoadingUnsignedLibraries: true,
115: 			respondToAuthRequestsFromMainProcess: true,
116: 			correlationId: id
117: 		});
118: 		const pid = await Event.toPromise(extHost.onSpawn);
119: 		return { pid };
120: 	}
121: 
122: 	async enableInspectPort(id: string): Promise<boolean> {
123: 		if (this._shutdown) {
124: 			throw canceled();
125: 		}
126: 		const extHostProcess = this._extHosts.get(id);
127: 		if (!extHostProcess) {
128: 			return false;
129: 		}
130: 		return extHostProcess.enableInspectPort();
131: 	}
132: 
133: 	async kill(id: string): Promise<void> {
134: 		if (this._shutdown) {
135: 			throw canceled();
136: 		}
137: 		const extHostProcess = this._extHosts.get(id);
138: 		if (!extHostProcess) {
139: 			// already gone!
140: 			return;
141: 		}
142: 		extHostProcess.kill();
143: 	}
144: 
145: 	async _killAllNow(): Promise<void> {
146: 		for (const [, extHost] of this._extHosts) {
147: 			extHost.kill();
148: 		}
149: 	}
150: 
151: 	async _waitForAllExit(maxWaitTimeMs: number): Promise<void> {
152: 		const exitPromises: Promise<void>[] = [];
153: 		for (const [, extHost] of this._extHosts) {
154: 			exitPromises.push(extHost.waitForExit(maxWaitTimeMs));
155: 		}
156: 		return Promises.settled(exitPromises).then(() => { });
157: 	}
158: }
