22: export interface IUtilityProcessConfiguration {
23: 
24: 	/**
25: 	 * A way to group utility processes of same type together.
26: 	 */
27: 	readonly type: string;
28: 
29: 	/**
30: 	 * The entry point to load in the utility process.
31: 	 */
32: 	readonly entryPoint: string;
33: 
34: 	/**
35: 	 * An optional serializable object to be sent into the utility process
36: 	 * as first message alongside the message port.
37: 	 */
38: 	readonly payload?: unknown;
39: 
40: 	/**
41: 	 * Environment key-value pairs. Default is `process.env`.
42: 	 */
43: 	readonly env?: { [key: string]: string | undefined };
44: 
45: 	/**
46: 	 * List of string arguments that will be available as `process.argv`
47: 	 * in the child process.
48: 	 */
49: 	readonly args?: string[];
50: 
51: 	/**
52: 	 * List of string arguments passed to the executable.
53: 	 */
54: 	readonly execArgv?: string[];
55: 
56: 	/**
57: 	 * Allow the utility process to load unsigned libraries.
58: 	 */
59: 	readonly allowLoadingUnsignedLibraries?: boolean;
60: 
61: 	/**
62: 	 * Used in log messages to correlate the process
63: 	 * with other components.
64: 	 */
65: 	readonly correlationId?: string;
66: 
67: 	/**
68: 	 * Optional pid of the parent process. If set, the
69: 	 * utility process will be terminated when the parent
70: 	 * process exits.
71: 	 */
72: 	readonly parentLifecycleBound?: number;
73: 
74: 	/**
75: 	 * HTTP 401 and 407 requests created via electron:net module
76: 	 * will be redirected to the main process and can be handled
77: 	 * via the app#login event.
78: 	 */
79: 	readonly respondToAuthRequestsFromMainProcess?: boolean;
80: }
81: 
