83: 
84: 	// --- message port response related
85: 
86: 	readonly responseWindowId: number;
87: 	readonly responseChannel: string;
88: 	readonly responseNonce: string;
89: 
90: 	// --- utility process options
91: 
92: 	/**
93: 	 * If set to `true`, will terminate the utility process
94: 	 * when the associated browser window closes or reloads.
95: 	 */
96: 	readonly windowLifecycleBound?: boolean;
97: }
98: 
99: function isWindowUtilityProcessConfiguration(config: IUtilityProcessConfiguration): config is IWindowUtilityProcessConfiguration {
100: 	const candidate = config as IWindowUtilityProcessConfiguration;
101: 
102: 	return typeof candidate.responseWindowId === 'number';
103: }
