140: export class UtilityProcess extends Disposable {
141: 
142: 	private static ID_COUNTER = 0;
143: 
144: 	private static readonly all = new Map<number, IUtilityProcessInfo>();
145: 	static getAll(): IUtilityProcessInfo[] {
146: 		return Array.from(UtilityProcess.all.values());
147: 	}
148: 
149: 	private readonly id = String(++UtilityProcess.ID_COUNTER);
150: 
151: 	private readonly _onStdout = this._register(new Emitter<string>());
152: 	readonly onStdout = this._onStdout.event;
153: 
154: 	private readonly _onStderr = this._register(new Emitter<string>());
155: 	readonly onStderr = this._onStderr.event;
156: 
157: 	private readonly _onMessage = this._register(new Emitter<unknown>());
158: 	readonly onMessage = this._onMessage.event;
159: 
160: 	private readonly _onSpawn = this._register(new Emitter<number | undefined>());
161: 	readonly onSpawn = this._onSpawn.event;
162: 
163: 	private readonly _onExit = this._register(new Emitter<IUtilityProcessExitEvent>());
164: 	readonly onExit = this._onExit.event;
165: 
166: 	private readonly _onCrash = this._register(new Emitter<IUtilityProcessCrashEvent>());
167: 	readonly onCrash = this._onCrash.event;
168: 
169: 	private process: ElectronUtilityProcess | undefined = undefined;
170: 	private processPid: number | undefined = undefined;
171: 	private configuration: IUtilityProcessConfiguration | undefined = undefined;
172: 
173: 	constructor(
174: 		@ILogService private readonly logService: ILogService,
175: 		@ITelemetryService private readonly telemetryService: ITelemetryService,
176: 		@ILifecycleMainService protected readonly lifecycleMainService: ILifecycleMainService
177: 	) {
178: 		super();
179: 	}
180: 
181: 	protected log(msg: string, severity: Severity): void {
182: 		let logMsg: string;
183: 		if (this.configuration?.correlationId) {
184: 			logMsg = `[UtilityProcess id: ${this.configuration?.correlationId}, type: ${this.configuration?.type}, pid: ${this.processPid ?? '<none>'}]: ${msg}`;
185: 		} else {
186: 			logMsg = `[UtilityProcess type: ${this.configuration?.type}, pid: ${this.processPid ?? '<none>'}]: ${msg}`;
187: 		}
188: 
189: 		switch (severity) {
190: 			case Severity.Error:
191: 				this.logService.error(logMsg);
192: 				break;
193: 			case Severity.Warning:
194: 				this.logService.warn(logMsg);
195: 				break;
196: 			case Severity.Info:
197: 				this.logService.trace(logMsg);
198: 				break;
199: 		}
200: 	}
201: 
202: 	private validateCanStart(): boolean {
203: 		if (this.process) {
204: 			this.log('Cannot start utility process because it is already running...', Severity.Error);
205: 
206: 			return false;
207: 		}
208: 
209: 		return true;
210: 	}
211: 
212: 	start(configuration: IUtilityProcessConfiguration): boolean {
213: 		const started = this.doStart(configuration);
214: 
215: 		if (started && configuration.payload) {
216: 			const posted = this.postMessage(configuration.payload);
217: 			if (posted) {
218: 				this.log('payload sent via postMessage()', Severity.Info);
219: 			}
220: 		}
221: 
222: 		return started;
223: 	}
224: 
225: 	protected doStart(configuration: IUtilityProcessConfiguration): boolean {
226: 		if (!this.validateCanStart()) {
227: 			return false;
228: 		}
229: 
230: 		this.configuration = configuration;
231: 
232: 		const serviceName = `${this.configuration.type}-${this.id}`;
233: 		const modulePath = FileAccess.asFileUri('bootstrap-fork.js').fsPath;
234: 		const args = this.configuration.args ?? [];
235: 		const execArgv = this.configuration.execArgv ?? [];
236: 		const allowLoadingUnsignedLibraries = this.configuration.allowLoadingUnsignedLibraries;
237: 		const respondToAuthRequestsFromMainProcess = this.configuration.respondToAuthRequestsFromMainProcess;
238: 		const stdio = 'pipe';
239: 		const env = this.createEnv(configuration);
240: 
241: 		this.log('creating new...', Severity.Info);
242: 
243: 		// Fork utility process
244: 		this.process = utilityProcess.fork(modulePath, args, {
245: 			serviceName,
246: 			env,
247: 			execArgv, // !!! Add `--trace-warnings` for node.js tracing !!!
248: 			allowLoadingUnsignedLibraries,
249: 			respondToAuthRequestsFromMainProcess,
250: 			stdio
251: 		});
252: 
253: 		// Register to events
254: 		this.registerListeners(this.process, this.configuration, serviceName);
255: 
256: 		return true;
257: 	}
258: 
259: 	private createEnv(configuration: IUtilityProcessConfiguration): { [key: string]: any } {
260: 		const env: { [key: string]: any } = configuration.env ? { ...configuration.env } : { ...deepClone(process.env) };
261: 
262: 		// Apply supported environment variables from config
263: 		env['VSCODE_ESM_ENTRYPOINT'] = configuration.entryPoint;
264: 		if (typeof configuration.parentLifecycleBound === 'number') {
265: 			env['VSCODE_PARENT_PID'] = String(configuration.parentLifecycleBound);
266: 		}
267: 		env['VSCODE_CRASH_REPORTER_PROCESS_TYPE'] = configuration.type;
268: 		if (isWindows) {
269: 			if (isUNCAccessRestrictionsDisabled()) {
270: 				env['NODE_DISABLE_UNC_ACCESS_CHECKS'] = '1';
271: 			} else {
272: 				env['NODE_UNC_HOST_ALLOWLIST'] = getUNCHostAllowlist().join('\\');
273: 			}
274: 		}
275: 
276: 		// Remove any environment variables that are not allowed
277: 		removeDangerousEnvVariables(env);
278: 
279: 		// Ensure all values are strings, otherwise the process will not start
280: 		for (const key of Object.keys(env)) {
281: 			env[key] = String(env[key]);
282: 		}
283: 
284: 		return env;
285: 	}
