152: 		const extensionsStatus = this.getExtensionsStatus();
153: 		for (const key of Object.keys(extensionsStatus)) {
154: 			const extensionStatus = extensionsStatus[key];
155: 			if (extensionStatus.activationStarted && extensionHost.containsExtension(extensionStatus.id)) {
156: 				activatedExtensions.push(extensionStatus.id);
157: 			}
158: 		}
159: 
160: 		super._onExtensionHostCrashed(extensionHost, code, signal);
161: 
162: 		if (extensionHost.kind === ExtensionHostKind.LocalProcess) {
163: 			if (code === ExtensionHostExitCode.VersionMismatch) {
164: 				this._notificationService.prompt(
165: 					Severity.Error,
