875: 	private async _onRemoteExtensionHostCrashed(extensionHost: IExtensionHostManager, reconnectionToken: string): Promise<void> {
876: 		try {
877: 			const info = await this._getExtensionHostExitInfoWithTimeout(reconnectionToken);
878: 			if (info) {
879: 				this._logService.error(`Extension host (${extensionHost.friendyName}) terminated unexpectedly with code ${info.code}.`);
880: 			}
881: 
882: 			this._logExtensionHostCrash(extensionHost);
883: 			this._remoteCrashTracker.registerCrash();
884: 
885: 			if (this._remoteCrashTracker.shouldAutomaticallyRestart()) {
886: 				this._logService.info(`Automatically restarting the remote extension host.`);
887: 				this._notificationService.status(nls.localize('extensionService.autoRestart', "The remote extension host terminated unexpectedly. Restarting..."), { hideAfter: 5000 });
888: 				this._startExtensionHostsIfNecessary(false, Array.from(this._allRequestedActivateEvents.keys()));
889: 			} else {
890: 				this._notificationService.prompt(Severity.Error, nls.localize('extensionService.crash', "Remote Extension host terminated unexpectedly 3 times within the last 5 minutes."),
891: 					[{
892: 						label: nls.localize('restart', "Restart Remote Extension Host"),
893: 						run: () => {
894: 							this._startExtensionHostsIfNecessary(false, Array.from(this._allRequestedActivateEvents.keys()));
895: 						}
896: 					}]
897: 				);
898: 			}
899: 		} catch (err) {
900: 			// maybe this wasn't an extension host crash and it was a permanent disconnection
901: 		}
902: 	}
