905: 
906: 		const activatedExtensions: ExtensionIdentifier[] = [];
907: 		for (const extensionStatus of this._extensionStatus.values()) {
908: 			if (extensionStatus.activationStarted && extensionHost.containsExtension(extensionStatus.id)) {
909: 				activatedExtensions.push(extensionStatus.id);
910: 			}
911: 		}
912: 
913: 		if (activatedExtensions.length > 0) {
914: 			this._logService.error(`Extension host (${extensionHost.friendyName}) terminated unexpectedly. The following extensions were running: ${activatedExtensions.map(id => id.value).join(', ')}`);
915: 		} else {
916: 			this._logService.error(`Extension host (${extensionHost.friendyName}) terminated unexpectedly. No extensions were activated.`);
917: 		}
918: 	}
